-- ═══════════════════════════════════════════════════════════════════════════════
-- ctjot.lua — game module for the Archipelago BizHawk connector.
--            Chrono Trigger: Jets of Time (SNES)
--
-- STATUS: REAL implementation, SOURCE-DERIVED from the CTJoT apworld's SNIClient
-- subclass. The 193-entry location table was GENERATED by parsing the source with
-- Python (ast) — the three flag dicts the client actually scans, JOINed by NAME
-- with data/location_data.json (loc_id = LOCATION_ID_START + value) — not hand-
-- copied, so it is exact. Addresses + masks + item handshake are replicated 1:1
-- from worlds/ctjot/Client.py (class CTJoTSNIClient, game = "Chrono Trigger Jets
-- of Time"). Loads and runs crash-free on any ROM; self-disables on a non-AP
-- cartridge. Mock-verified through MoonSharp against synthetic SNES memory.
--   SOURCE: https://github.com/Anguirel86/Archipelago (branch "ctjot")
--           worlds/ctjot/Client.py + worlds/ctjot/data/location_data.json
--           (the same source the ctjot.apworld ships from)
--
-- HOW CTJoT IS DISTRIBUTED (important — like FF1, NOT a normal AP patch)
-- ──────────────────────────────────────────────────────────────────────
--   The apworld has NO generate_output / APProcedurePatch — there is no .apctjot
--   file. The player generates a patched ROM (.sfc) + matching .yaml together from
--   the CTJoT web generator (https://multiworld.ctjot.com), uploading their own US
--   Chrono Trigger ROM. That ALREADY-PATCHED .sfc is the ROM loaded here. The
--   patched ROM carries the "AP" signature this module validates.
--
-- MEMORY MODEL (SNI → BizHawk SNES domains)
-- ──────────────────────────────────────────
--   CTJoT is an SNIClient SNES game. Client.py's _convert_to_sni_addressing(a) =
--   (a - 0x7E0000) + WRAM_START(0xF50000), so its $7E/$7F work-RAM addresses are
--   all BizHawk "WRAM"-domain offsets (= SNES addr - 0x7E0000):
--     • EVENT block  $7F0000        → WRAM offset 0x10000 (0x200 bytes; all the
--                                     event + treasure "checked" flags)
--     • map id       0xF50100 (SNI) → WRAM offset 0x00100 (2 bytes, little-endian)
--     • RECV item    $7E287A        → WRAM offset 0x0287A (u8 — id to grant)
--     • RECV count   $7E287C        → WRAM offset 0x0287C (u8 — items consumed)
--   The AP "AP" signature the client validates (VALIDATION_ADDR, already SNI ROM
--   addressing) is in the cartridge ROM ("CARTROM") at 0x3F8C03.
--
-- HOW CTJoT CHECKS WORK (a flag scan, like ALttP — not a SEND/RECV queue)
--   Client.py._track_locations does ONE 0x200-byte read of the event block and
--   tests each location's (byte, bitmask). The client scans exactly three dicts:
--     • _locations_baseline_key_items : event   data[addr - 0x7F0000] & flag
--     • _locations_event_treasures    : event   data[addr - 0x7F0000] & flag
--     • _locations_treasure_chests    : chest   data[offset + 1]       & flag
--   The other dicts (_locations_tab_events, _locations_misc_events,
--   _locations_treasure_chests_not_in_logic) are NOT scanned and are excluded.
--   The table below stores the FINAL block-relative byte offset for both flavours,
--   so each entry collapses to  event_block[byteoff] & mask.
--
-- WHAT THIS DOES (mirrors worlds/ctjot/Client.py)
--   • poll(): the client's _track_locations scan → AP location ids, gated to the
--     slot's server location set AND the same in-game gate the client uses (not in
--     the "@ABC" gate-travel mode-7 scene, map id ∉ {0x00,0x1B1}, map id ≤ 0x1FF).
--   • is_goal_complete(): the multiworld victory flag — event_block[0x20] & 0x01
--     (VICTORY_ADDRESS $7F0020), the cross-mode/cross-ending completion bit the
--     CTJoT multiworld code adds to the ending selector scene.
--   • receive_item(): the client's _deliver_next_item handshake. items_handling =
--     0b011, so the server streams our own world's items too (the in-game event
--     code grants every received item). The game owns RECV count and its event
--     code zeroes the RECV slot once it consumes an item, so we only write the next
--     item when (a) count < #delivered and (b) the RECV slot is 0. In-game item ids
--     are item.item - ITEM_ID_START; only real items (id ≤ 255) are written to the
--     slot — event-only items (character pickups, id > 255) are skipped but still
--     advance the count, exactly as the client does.
--
-- MODULE CONTRACT (called by bizhawk_ap_connector.lua)
--   M.init(ctx) / M.poll() -> {ids} / M.is_goal_complete() -> bool /
--   M.receive_item(item_id, meta)
-- ═══════════════════════════════════════════════════════════════════════════════

local M = {}
M.name = "ctjot"

-- Location ids are ABSOLUTE (LOCATION_ID_START + value, both from the apworld), so
-- detection is fully self-contained — no per-slot data-package base is needed and
-- this stays true (same situation as ALttP / cvcotm, unlike Super Metroid).
local ADDRESSES_VERIFIED = true

-- ── Memory domains ────────────────────────────────────────────────────────────
local WRAM    = "WRAM"
local CARTROM = "CARTROM"     -- SNES cartridge ROM in BizHawk; fallback "ROM"

-- ── SNI-space constants, as BizHawk-domain offsets (Client.py module top) ─────
local EVENT_BLOCK_OFF = 0x10000          -- WRAM: $7F0000 event block base
local EVENT_BLOCK_SIZE= 0x200            -- bytes the client reads in one go
local MAPID_OFF       = 0x00100          -- WRAM: map id (LOCATION_ADDRESS 0xF50100)
local RECV_ITEM_OFF   = 0x0287A          -- WRAM: RECEIVE_ITEM_ADDR  $7E287A (u8)
local RECV_COUNT_OFF  = 0x0287C          -- WRAM: RECEIVED_ITEM_COUNT $7E287C (u8)
local VICTORY_OFF     = 0x20             -- within event block: VICTORY_ADDRESS $7F0020
local VICTORY_MASK    = 0x01

local ROMNAME_OFF     = 0x3F8C03         -- CARTROM: VALIDATION_ADDR; first 2 = "AP"

-- Item id math (Client.py).
local ITEM_ID_START      = 5100000
local MAX_IN_GAME_ITEM_ID= 255

-- Tracking gate (Client.py._track_locations).
local INVALID_TRACKING_MAPS = { [0x00]=true, [0x1B1]=true }  -- load / title screens
local MAX_MAP_ID            = 0x1FF
local GATE_TRAVEL_SIG       = { 0x40, 0x41, 0x42, 0x43 }       -- "@ABC" mode-7 pattern

