-- ── Internal state ────────────────────────────────────────────────────────────
local reported        = {}     -- ap_id -> true once returned from poll()
local server_locations= nil     -- set of ap_ids the server expects (nil = all)
local items_received  = {}     -- ordered stream (extended ITEM lines)
local slot_number     = 0
local rom_ok          = nil     -- cached "AP" signature result (nil until checked)
local mem             = {}
local log_fn          = nil
local event_block     = {}      -- byte offset -> value, refreshed each poll

-- ── Logging ───────────────────────────────────────────────────────────────────
local function log(msg)
  if log_fn then pcall(log_fn, "[ctjot] " .. tostring(msg)) end
end

-- ── Memory API (resolved at init; 2-arg domain form + current-domain fallback) ─
local function resolve_memory_api()
  if not memory then return false end
  mem.read_u8   = memory.read_u8     or memory.readbyte
  mem.read_u16  = memory.read_u16_le or memory.readword
  mem.write_u8  = memory.write_u8    or memory.writebyte
  return mem.read_u8 ~= nil
end

local function rd(fn, addr, domain)
  if not fn then return nil end
  local ok, v = pcall(fn, addr, domain)
  if ok and type(v) == "number" then return v end
  ok, v = pcall(fn, addr)                       -- older API: current domain
  if ok and type(v) == "number" then return v end
  return nil
end

local function read_u8(addr, domain)  return rd(mem.read_u8,  addr, domain or WRAM) end
local function read_u16(addr, domain) return rd(mem.read_u16, addr, domain or WRAM) end

local function write_u8(addr, value, domain)
  if not mem.write_u8 then return end
  if pcall(mem.write_u8, addr, value, domain or WRAM) then return end
  pcall(mem.write_u8, addr, value)
end

-- Read from CARTROM, falling back to the legacy "ROM" domain name on cores that use it.
local function read_cartrom_u8(off)
  local ok, v = pcall(mem.read_u8, off, CARTROM)
  if ok and type(v) == "number" then return v end
  ok, v = pcall(mem.read_u8, off, "ROM")
  if ok and type(v) == "number" then return v end
  return nil
end

local function bit_and(a, b)
  -- 8-bit-safe AND without the bit library (cores vary).
  local res, bitval = 0, 1
  while a > 0 and b > 0 do
    if a % 2 == 1 and b % 2 == 1 then res = res + bitval end
    a = math.floor(a / 2); b = math.floor(b / 2); bitval = bitval * 2
  end
  return res
end

-- ── ROM identity: the AP-patched ROM carries "AP" at CARTROM 0x3F8C03 ─────────
local function rom_is_ap()
  if rom_ok ~= nil then return rom_ok end
  local a = read_cartrom_u8(ROMNAME_OFF)
  local p = read_cartrom_u8(ROMNAME_OFF + 1)
  if a == nil or p == nil then return false end          -- not readable yet; retry
  rom_ok = (a == string.byte("A") and p == string.byte("P"))
  if rom_ok then log("AP ROM verified ('AP' signature present)")
  else log("non-AP ROM (no 'AP' signature) — detection idle, no writes") end
  return rom_ok
end

-- ── Multiworld context ────────────────────────────────────────────────────────
local function load_locations(ids)
  if type(ids) ~= "table" then return end
  server_locations = {}
  local n = 0
  for _, id in ipairs(ids) do
    local v = tonumber(id)
    if v then server_locations[v] = true; n = n + 1 end
  end
  log("server location set: " .. n .. " ids")
end

local function wanted(ap_id)
  if server_locations == nil then return true end   -- no set provided → report all
  return server_locations[ap_id] == true
end

-- Item-stream filter. CTJoT uses items_handling = 0b011 (it WANTS its own world's
-- found items back too — the in-game event code grants every received item), so we
-- do NOT drop own-world items the way the items_handling=1 modules do. We only drop
-- pure server/starting-inventory placeholders (player 0 with no real location).
local function accept_item(it)
  if it.player == nil then return true end          -- legacy ITEM:<id> line
  if it.player == 0 and (it.location or 0) <= 0 then return false end
  return true
end

local function delivery_list()
  local out = {}
  for _, it in ipairs(items_received) do
    if accept_item(it) then out[#out + 1] = it end
  end
  return out
end

-- ── Detection gate (Client.py._track_locations) ───────────────────────────────
local function refresh_event_block()
  for i = 0, EVENT_BLOCK_SIZE - 1 do
    event_block[i] = read_u8(EVENT_BLOCK_OFF + i)
  end
end

-- True when it is SAFE to read checks: not in the gate-travel mode-7 scene (which
-- overwrites event RAM with the "@ABC" pattern), and on a real, in-range map.
local function tracking_ok()
  -- Gate-travel detection: event_block[0..3] == "@ABC".
  local b0,b1,b2,b3 = event_block[0], event_block[1], event_block[2], event_block[3]
  if b0 == GATE_TRAVEL_SIG[1] and b1 == GATE_TRAVEL_SIG[2]
     and b2 == GATE_TRAVEL_SIG[3] and b3 == GATE_TRAVEL_SIG[4] then
    return false
  end
  -- Map id (2 bytes LE at WRAM 0x0100). Skip load/title screens and out-of-range.
  local map_id = read_u16(MAPID_OFF)
  if map_id == nil then return false end
  if INVALID_TRACKING_MAPS[map_id] then return false end
  if map_id > MAX_MAP_ID then return false end
  return true
end

local function flag_set(byteoff, mask)
  local v = event_block[byteoff]
  if v == nil then return false end
  return bit_and(v, mask) ~= 0
end

-- ── Module contract ───────────────────────────────────────────────────────────

function M.init(ctx)
  if ctx and type(ctx.log) == "function" then log_fn = ctx.log end
  if not resolve_memory_api() then
    log("BizHawk memory API unavailable — module idle")
    ADDRESSES_VERIFIED = false
    return
  end
  local cfg = (ctx and ctx.config) or {}
  slot_number = tonumber(cfg.slot_number) or 0
  load_locations(cfg.locations)
  local n = 0; for _ in pairs(LOC) do n = n + 1 end
  log(("ready: slot #%d, %d location flags"):format(slot_number, n))
end

function M.poll()
  local new = {}
  if not ADDRESSES_VERIFIED then return new end
  if not rom_is_ap() then return new end
  refresh_event_block()
  if not tracking_ok() then return new end
  for ap_id, bm in pairs(LOC) do
    if not reported[ap_id] and wanted(ap_id) and flag_set(bm[1], bm[2]) then
      reported[ap_id] = true
      new[#new + 1] = ap_id
    end
  end
  return new
end

function M.is_goal_complete()
  if not ADDRESSES_VERIFIED or not rom_is_ap() then return false end
  refresh_event_block()
  return flag_set(VICTORY_OFF, VICTORY_MASK)
end

-- Record the grant, then push the next pending item to the game when the game is
-- ready for it — the client's _deliver_next_item handshake. The game owns the RECV
-- count and its event code zeroes the RECV slot once it consumes an item; we only
-- write the next item when count < #delivered AND the slot is empty (0). Event-only
-- AP items (character pickups, in-game id > MAX_IN_GAME_ITEM_ID) are not written to
-- the slot but still advance the count, exactly like the client.
function M.receive_item(item_id, meta)
  if type(meta) == "table" then
    items_received[#items_received + 1] = {
      item     = tonumber(item_id),
      index    = tonumber(meta.index),
      player   = tonumber(meta.player),
      flags    = tonumber(meta.flags),
      location = tonumber(meta.locId or meta.location),
    }
  else
    items_received[#items_received + 1] = { item = tonumber(item_id) }
  end

  if not ADDRESSES_VERIFIED or not rom_is_ap() then return end

  local list = delivery_list()
  local count = read_u8(RECV_COUNT_OFF)
  if count == nil then return end
  if count < #list then
    local slot = read_u8(RECV_ITEM_OFF)
    if slot == nil or slot ~= 0 then return end          -- game hasn't consumed last item yet
    local nxt = list[count + 1]
    if nxt and nxt.item then
      local in_game_id = nxt.item - ITEM_ID_START
      -- Only real in-game items (id ≤ 255) are written to the receive slot; event
      -- items (character pickups) are skipped but the count still advances.
      if in_game_id >= 0 and in_game_id <= MAX_IN_GAME_ITEM_ID then
        write_u8(RECV_ITEM_OFF, bit_and(in_game_id, 0xFF))
      end
      -- The client writes the count back manually (the event scripts can't reach
      -- this RAM); mirror that so the next poll feeds list[count+2], and so on.
      write_u8(RECV_COUNT_OFF, bit_and(count + 1, 0xFF))
    end
  end
end

return M
